/// <summary>
/// Extension class of <c>SalesInvoiceDP</c> for text block management
/// </summary>
[ExtensionOf(classStr(SalesInvoiceDP))]
final class FWFTextBlockSalesInvoiceDP_Extension
{
}

Method.Source:
protected void populateSalesInvoiceTmp(CustInvoiceJour _custInvoiceJour, CustInvoiceTrans _custInvoiceTrans, TaxSpec _taxSpec, CustPaymSchedLine _custPaymSchedLine, CustTrans _prepaymentCustTrans, TaxTrans _prepaymentTaxTrans)
{
    next populateSalesInvoiceTmp(_custInvoiceJour, _custInvoiceTrans, _taxSpec, _custPaymSchedLine, _prepaymentCustTrans, _prepaymentTaxTrans);

    if (!this.salesInvoiceTmp.TaxCode)
    {
        FWFTextBlockReportTextInit::newParameters(this.salesInvoiceTmp, _custInvoiceTrans).addTexts();
    }
}
